EOLopt = (_ "\n")?

input:
interface BaseRecord {
  target: number;
  owner?: string[];
  result: string;
  summary: 'capacity' | 'ttl' | 'manual';
  active: number;
  startTime: string;
}

output:
BaseRecord
  = target:TargetSection EOL result:ResultSection EOL summary:SummarySection EOL active:ActiveSection EOL startTime:StartTimeSection owner:OwnerOpt EOLopt
    { return { target: target, result: result, summary: summary, active: active, startTime: startTime, owner: owner }; }

TargetSection
  = "TARGET:" _ v:Integer { return v; }

ResultSection
  = "RESULT:" _ v:QuotedString { return v; }

SummarySection
  = "SUMMARY:" _ v:("capacity" / "ttl" / "manual") { return v; }

ActiveSection
  = "ACTIVE:" _ v:Float { return v; }

StartTimeSection
  = "START_TIME:" _ v:QuotedString { return v; }

OwnerOpt
  = EOL "OWNER:" _ v:QuotedString { return v; }
  / "" { return undefined; }

Identifier = chars:$[a-zA-Z0-9_-]+ { return chars; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$([0-9]+ ("." [0-9]+)?) { return parseFloat(chars); }
Integer = chars:$[0-9]+ { return parseInt(chars, 10); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

