Bool = "yes" { return true; } / "no" { return false; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Integer = chars:$[0-9]+ { return parseInt(chars, 10); }
_ = [ \t]*
EOL = _ "\n"
