  = "RESULT:" _ v:("open" / "closed" / "archived") { return v; }

IntervalSection
  = "INTERVAL:" _ "none" { return []; }
  / "INTERVAL:" _ first:IntervalValue rest:("," _ v:IntervalValue { return v; })* { return [first, ...rest]; }

